formulas.expression:
IF(
    CONTAINS(
        SUBSTITUTE({!CreateTempPINApproverMobile}, " ", ""), 
        {!Get_Shift_PIN_Custom_Meta_Config.Temp_PIN_Internation_Phone_Currency_Code__c}
    ),
    /* If the phone already contains the dial code */
    SUBSTITUTE({!CreateTempPINApproverMobile}, " ", ""),
    /* Else: remove spaces, strip leading 0, and add dial code */
    {!Get_Shift_PIN_Custom_Meta_Config.Temp_PIN_Internation_Phone_Currency_Code__c} &
    IF(
        LEFT(SUBSTITUTE({!CreateTempPINApproverMobile}, " ", ""), 1) = "0",
        MID(SUBSTITUTE({!CreateTempPINApproverMobile}, " ", ""), 2, LEN(SUBSTITUTE({!CreateTempPINApproverMobile}, " ", "")) - 1),
        SUBSTITUTE({!CreateTempPINApproverMobile}, " ", "")
    )
)

IF( ISBLANK({!Get_Full_Initial_TS_Approver_based_on_PIN.Id}),
/* --------------------------- USE Get_TS_Approver_Full_record_Signature_Only --------------------------- */ IF( {!Get_TS_Approver_Full_record_Signature_Only.RecordType.DeveloperName} = "Standard_Approver", CONTAINS(TEXT({!Get_TS_Approver_Full_record_Signature_Only.Approval_Method__c}), "Signature"), IF( {!Get_TS_Approver_Full_record_Signature_Only.RecordType.DeveloperName} = "Temporary_Approver", CONTAINS(TEXT({!Get_TS_Approver_Full_record_Signature_Only.Account__r.Secondary_Approval_Method__c}), "Signature"), TRUE ) ),
/* --------------------------- ELSE use Get_Full_Initial_TS_Approver_based_on_PIN --------------------------- */ IF( {!Get_Full_Initial_TS_Approver_based_on_PIN.RecordType.DeveloperName} = "Standard_Approver", CONTAINS(TEXT({!Get_Full_Initial_TS_Approver_based_on_PIN.Approval_Method__c}), "Signature"), IF( {!Get_Full_Initial_TS_Approver_based_on_PIN.RecordType.DeveloperName} = "Temporary_Approver", CONTAINS(TEXT({!Get_Full_Initial_TS_Approver_based_on_PIN.Account__r.Secondary_Approval_Method__c}), "Signature"), TRUE ) ) )
